example.code:
{
  "name": "code-reviewer",
  "description": "Reviews a diff against the project's coding conventions; returns a structured JSON of findings.",
  "tools": [
    "Read",
    "Grep",
    "Glob"
  ],
  "model": "sonnet",
  "output_contract": {
    "kind": "json",
    "schema_uri": "schemas/review.json"
  },
  "max_tokens": 8000
}
